/* Umoria 5.6 - single file Linux build
 *
 * Compile:
 *   gcc moria.c -lncurses -DLIBDIR=\"$HOME/.local/share/moria\" -o moria
 *
 * Install data files (first time only):
 *   mkdir -p ~/.local/share/moria
 *   cp -r files/. ~/.local/share/moria/
 *   touch ~/.local/share/moria/scores
 *   chmod 644 ~/.local/share/moria/scores
 */

/* ================================================================
 * Linux system headers - must come before project headers so that
 * declarations like SIGTSTP and open() are in place before externs.h
 * redefines them.
 * ================================================================ */
#include <assert.h>
#include <ctype.h>
#include <curses.h>
#include <errno.h>
#include <fcntl.h>
#include <pwd.h>
#include <signal.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <strings.h>
#include <sys/file.h>
#include <sys/ioctl.h>
#include <sys/param.h>
#include <sys/resource.h>
#include <sys/select.h>
#include <sys/stat.h>
#include <sys/time.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <termios.h>
#include <time.h>
#include <unistd.h>

