int set_room(element)
int element;
{
    if ((element == DARK_FLOOR) || (element == LIGHT_FLOOR))
        return (TRUE);
    return (FALSE);
}

int set_corr(element)
int element;
{
    if (element == CORR_FLOOR || element == BLOCKED_FLOOR)
        return (TRUE);
    return (FALSE);
}

int set_floor(element)
int element;
{
    if (element <= MAX_CAVE_FLOOR)
        return (TRUE);
    else
        return (FALSE);
}

int set_corrodes(item)
inven_type *item;
{
    switch (item->item_category) {
    case TV_SWORD:
    case TV_HELM:
    case TV_SHIELD:
    case TV_HARD_ARMOR:
    case TV_WAND:
        return (TRUE);
    }
    return (FALSE);
}

int set_flammable(item)
inven_type *item;
{
    switch (item->item_category) {
    case TV_ARROW:
    case TV_BOW:
    case TV_HAFTED:
    case TV_POLEARM:
    case TV_BOOTS:
    case TV_GLOVES:
    case TV_CLOAK:
    case TV_SOFT_ARMOR:
        /* Items of (RF) should not be destroyed.  */
        if (item->flags & TR_RES_FIRE)
            return FALSE;
        else
            return TRUE;

    case TV_STAFF:
    case TV_SCROLL1:
    case TV_SCROLL2:
        return TRUE;
    }
    return (FALSE);
}

int set_frost_destroy(item)
inven_type *item;
{
    if ((item->item_category == TV_POTION1) ||
        (item->item_category == TV_POTION2) ||
        (item->item_category == TV_FLASK))
        return (TRUE);
    return (FALSE);
}

int set_acid_affect(item)
inven_type *item;
{
    switch (item->item_category) {
    case TV_MISC:
    case TV_CHEST:
        return TRUE;
    case TV_BOLT:
    case TV_ARROW:
    case TV_BOW:
    case TV_HAFTED:
    case TV_POLEARM:
    case TV_BOOTS:
    case TV_GLOVES:
    case TV_CLOAK:
    case TV_SOFT_ARMOR:
        if (item->flags & TR_RES_ACID)
            return (FALSE);
        else
            return (TRUE);
    }
    return (FALSE);
}

int set_lightning_destroy(item)
inven_type *item;
{
    if ((item->item_category == TV_RING) || (item->item_category == TV_WAND) ||
        (item->item_category == TV_SPIKE))
        return (TRUE);
    else
        return (FALSE);
}

