#ifdef MAC
/* The last time tried, MPW failed to handle the initialized array of
   function pointers properly.  hence, this hack. */
int store_buy(storeno, element)
int storeno;
int element;
{
    switch (storeno) {
    case 0:
        return (general_store(element));
    case 1:
        return (armory(element));
    case 2:
        return (weaponsmith(element));
    case 3:
        return (temple(element));
    case 4:
        return (alchemist(element));
    case 5:
        return (magic_shop(element));
    }
    return (FALSE);
}
#endif

