/* Adjustment for wisdom/intelligence                           -JWT-   */
int get_mana_multiplier(stat)
int stat;
{
    int value;

    value = py.stats.use_stat[stat];
    if (value > 117)
        return (7);
    else if (value > 107)
        return (6);
    else if (value > 87)
        return (5);
    else if (value > 67)
        return (4);
    else if (value > 17)
        return (3);
    else if (value > 14)
        return (2);
    else if (value > 7)
        return (1);
    else
        return (0);
}

/* Adjustment for charisma                              -RAK-   */
/* Percent decrease or increase in price of goods                */
int chr_adj() {
    int charisma;

    charisma = py.stats.use_stat[A_CHR];
    if (charisma > 117)
        return (90);
    else if (charisma > 107)
        return (92);
    else if (charisma > 87)
        return (94);
    else if (charisma > 67)
        return (96);
    else if (charisma > 18)
        return (98);
    else
        switch (charisma) {
        case 18:
            return (100);
        case 17:
            return (101);
        case 16:
            return (102);
        case 15:
            return (103);
        case 14:
            return (104);
        case 13:
            return (106);
        case 12:
            return (108);
        case 11:
            return (110);
        case 10:
            return (112);
        case 9:
            return (114);
        case 8:
            return (116);
        case 7:
            return (118);
        case 6:
            return (120);
        case 5:
            return (122);
        case 4:
            return (125);
        case 3:
            return (130);
        default:
            return (100);
        }
}

/* Returns a character's adjustment to hit points        -JWT-   */
int con_adj() {
    int con;

    con = py.stats.use_stat[A_CON];
    if (con < 7)
        return (con - 7);
    else if (con < 17)
        return (0);
    else if (con == 17)
        return (1);
    else if (con < 94)
        return (2);
    else if (con < 117)
        return (3);
    else
        return (4);
}

char *title_string() {
    char *p;

    if (py.misc.level < 1)
        p = "Babe in arms";
    else if (py.misc.level <= MAX_PLAYER_LEVEL)
        p = player_title[py.misc.pclass][py.misc.level - 1];
    else if (py.misc.male)
        p = "**KING**";
    else
        p = "**QUEEN**";
    return p;
}

