/* Prints winner status on display                      -RAK-   */
void prt_winner() {
    if (noscore & 0x2) {
        if (wizard)
            put_buffer("Is wizard  ", 22, 0);
        else
            put_buffer("Was wizard ", 22, 0);
    } else if (noscore & 0x1)
        put_buffer("Resurrected", 22, 0);
    else if (noscore & 0x4)
        put_buffer("Duplicate", 22, 0);
    else if (total_winner)
        put_buffer("*Winner*   ", 22, 0);
}

int8u modify_stat(stat, amount)
int stat;
int16 amount;
{
    int loop, i;
    int8u tmp_stat;

    tmp_stat = py.stats.cur_stat[stat];
    loop = (amount < 0 ? -amount : amount);
    for (i = 0; i < loop; i++) {
        if (amount > 0) {
            if (tmp_stat < 18)
                tmp_stat++;
            else if (tmp_stat < 108)
                tmp_stat += 10;
            else
                tmp_stat = 118;
        } else {
            if (tmp_stat > 27)
                tmp_stat -= 10;
            else if (tmp_stat > 18)
                tmp_stat = 18;
            else if (tmp_stat > 3)
                tmp_stat--;
        }
    }
    return tmp_stat;
}

/* Set the value of the stat which is actually used.     -CJS- */
void set_use_stat(stat) int stat;
{
#ifdef ATARIST_MWC
    int32u holder;
#endif

    py.stats.use_stat[stat] = modify_stat(stat, py.stats.mod_stat[stat]);

    if (stat == A_STR) {
#ifdef ATARIST_MWC
        py.flags.status |= (holder = PY_STR_WGT);
#else
        py.flags.status |= PY_STR_WGT;
#endif
        calc_bonuses();
    } else if (stat == A_DEX)
        calc_bonuses();
    else if (stat == A_INT && class[py.misc.pclass].spell == MAGE) {
        calc_spells(A_INT);
        calc_mana(A_INT);
    } else if (stat == A_WIS && class[py.misc.pclass].spell == PRIEST) {
        calc_spells(A_WIS);
        calc_mana(A_WIS);
    } else if (stat == A_CON)
        calc_hitpoints();
}

/* Increases a stat by one randomized level             -RAK-   */
int inc_stat(stat)
int stat;
{
    int tmp_stat, gain;

    tmp_stat = py.stats.cur_stat[stat];
    if (tmp_stat < 118) {
        if (tmp_stat < 18)
            tmp_stat++;
        else if (tmp_stat < 116) {
            /* stat increases by 1/6 to 1/3 of difference from max */
            gain = ((118 - tmp_stat) / 3 + 1) >> 1;
            tmp_stat += randint(gain) + gain;
        } else
            tmp_stat++;

        py.stats.cur_stat[stat] = tmp_stat;
        if (tmp_stat > py.stats.max_stat[stat])
            py.stats.max_stat[stat] = tmp_stat;
        set_use_stat(stat);
        prt_stat(stat);
        return TRUE;
    } else
        return FALSE;
}

/* Decreases a stat by one randomized level             -RAK-   */
int dec_stat(stat)
int stat;
{
    int tmp_stat, loss;

    tmp_stat = py.stats.cur_stat[stat];
    if (tmp_stat > 3) {
        if (tmp_stat < 19)
            tmp_stat--;
        else if (tmp_stat < 117) {
            loss = (((118 - tmp_stat) >> 1) + 1) >> 1;
            tmp_stat += -randint(loss) - loss;
            if (tmp_stat < 18)
                tmp_stat = 18;
        } else
            tmp_stat--;

        py.stats.cur_stat[stat] = tmp_stat;
        set_use_stat(stat);
        prt_stat(stat);
        return TRUE;
    } else
        return FALSE;
}

/* Restore a stat.  Return TRUE only if this actually makes a difference. */
int res_stat(stat)
int stat;
{
    int i;

    i = py.stats.max_stat[stat] - py.stats.cur_stat[stat];
    if (i) {
        py.stats.cur_stat[stat] += i;
        set_use_stat(stat);
        prt_stat(stat);
        return TRUE;
    }
    return FALSE;
}

/* Boost a stat artificially (by wearing something). If the display argument
   is TRUE, then increase is shown on the screen. */
void bst_stat(stat, amount) int stat, amount;
{
#ifdef ATARIST_MWC
    int32u holder;
#endif

    py.stats.mod_stat[stat] += amount;

    set_use_stat(stat);
    /* can not call prt_stat() here, may be in store, may be in inven_command */
#ifdef ATARIST_MWC
    py.flags.status |= ((holder = PY_STR) << stat);
#else
    py.flags.status |= (PY_STR << stat);
#endif
}

/* Returns a character's adjustment to hit.              -JWT-   */
int tohit_adj() {
    int total, stat;

    stat = py.stats.use_stat[A_DEX];
    if (stat < 4)
        total = -3;
    else if (stat < 6)
        total = -2;
    else if (stat < 8)
        total = -1;
    else if (stat < 16)
        total = 0;
    else if (stat < 17)
        total = 1;
    else if (stat < 18)
        total = 2;
    else if (stat < 69)
        total = 3;
    else if (stat < 118)
        total = 4;
    else
        total = 5;
    stat = py.stats.use_stat[A_STR];
    if (stat < 4)
        total -= 3;
    else if (stat < 5)
        total -= 2;
    else if (stat < 7)
        total -= 1;
    else if (stat < 18)
        total -= 0;
    else if (stat < 94)
        total += 1;
    else if (stat < 109)
        total += 2;
    else if (stat < 117)
        total += 3;
    else
        total += 4;
    return (total);
}

/* Returns a character's adjustment to armor class       -JWT-   */
int toac_adj() {
    int stat;

    stat = py.stats.use_stat[A_DEX];
    if (stat < 4)
        return (-4);
    else if (stat == 4)
        return (-3);
    else if (stat == 5)
        return (-2);
    else if (stat == 6)
        return (-1);
    else if (stat < 15)
        return (0);
    else if (stat < 18)
        return (1);
    else if (stat < 59)
        return (2);
    else if (stat < 94)
        return (3);
    else if (stat < 117)
        return (4);
    else
        return (5);
}

/* Returns a character's adjustment to disarm            -RAK-   */
int todis_adj() {
    int stat;

    stat = py.stats.use_stat[A_DEX];
    if (stat < 4)
        return (-8);
    else if (stat == 4)
        return (-6);
    else if (stat == 5)
        return (-4);
    else if (stat == 6)
        return (-2);
    else if (stat == 7)
        return (-1);
    else if (stat < 13)
        return (0);
    else if (stat < 16)
        return (1);
    else if (stat < 18)
        return (2);
    else if (stat < 59)
        return (4);
    else if (stat < 94)
        return (5);
    else if (stat < 117)
        return (6);
    else
        return (8);
}

/* Returns a character's adjustment to damage            -JWT-   */
int todam_adj() {
    int stat;

    stat = py.stats.use_stat[A_STR];
    if (stat < 4)
        return (-2);
    else if (stat < 5)
        return (-1);
    else if (stat < 16)
        return (0);
    else if (stat < 17)
        return (1);
    else if (stat < 18)
        return (2);
    else if (stat < 94)
        return (3);
    else if (stat < 109)
        return (4);
    else if (stat < 117)
        return (5);
    else
        return (6);
}

/* Prints character-screen info                         -RAK-   */
void prt_stat_block() {
    u32i status;
    struct misc *m_ptr;
    int i;

    m_ptr = &py.misc;
    prt_field(race[py.misc.prace].trace, 2, STAT_COLUMN);
    prt_field(class[py.misc.pclass].title, 3, STAT_COLUMN);
    prt_field(title_string(), 4, STAT_COLUMN);
    for (i = 0; i < 6; i++)
        prt_stat(i);
    prt_num("LEV ", (int)m_ptr->level, 13, STAT_COLUMN);
    prt_lnum("EXP ", m_ptr->exp, 14, STAT_COLUMN);
    prt_num("MANA", m_ptr->int_mana, 15, STAT_COLUMN);
    prt_num("MHP ", m_ptr->mhp, 16, STAT_COLUMN);
    prt_num("CHP ", m_ptr->chp, 17, STAT_COLUMN);
    prt_num("AC  ", m_ptr->dis_ac, 19, STAT_COLUMN);
    prt_lnum("GOLD", m_ptr->au, 20, STAT_COLUMN);
    prt_winner();
    status = py.flags.status;
    if ((PY_HUNGRY | PY_WEAK) & status)
        prt_hunger();
    if (PY_BLIND & status)
        prt_blind();
    if (PY_CONFUSED & status)
        prt_confused();
    if (PY_FEAR & status)
        prt_afraid();
    if (PY_POISONED & status)
        prt_poisoned();
    if ((PY_SEARCH | PY_REST) & status)
        prt_state();
    /* if speed non zero, print it, modify speed if Searching */
    if (py.flags.speed - ((PY_SEARCH & status) >> 8) != 0)
        prt_speed();
    /* display the study field */
    prt_study();
}

