/* Returns a rating of x depending on y                 -JWT-   */
char *likert(x, y)
int x, y;
{
    switch ((x / y)) {
    case -3:
    case -2:
    case -1:
        return ("Very Bad");
    case 0:
    case 1:
        return ("Bad");
    case 2:
        return ("Poor");
    case 3:
    case 4:
        return ("Fair");
    case 5:
        return ("Good");
    case 6:
        return ("Very Good");
    case 7:
    case 8:
        return ("Excellent");
    default:
        return ("Superb");
    }
}

