/* defines for p1_use, determine how the p1 field is printed */
#define IGNORED 0
#define CHARGES 1
#define PLUSSES 2
#define LIGHT 3
#define FLAGS 4
#define Z_PLUSSES 5

/* Returns a description of item for inventory			*/
/* pref indicates that there should be an article added (prefix) */
/* note that since out_val can easily exceed 80 characters, objdes must
   always be called with a bigvtype as the first paramter */
void objdes(out_val, inventory_p, pref) char *out_val;
inven_type *inventory_p;
int pref;
{
    /* base name, modifier string*/
    char *basenm, *modstr;
    bigvtype tmp_val;
    vtype tmp_str, damstr;
    int indexx, p1_use, modify, append_name, tmp;

    indexx = inventory_p->item_subcategory & (ITEM_SINGLE_STACK_MIN - 1);
    basenm = object_list[inventory_p->index].name;
    modstr = CNIL;
    damstr[0] = '\0';
    p1_use = IGNORED;
    modify = (known1_p(inventory_p) ? FALSE : TRUE);
    append_name = FALSE;
    switch (inventory_p->item_category) {
    case TV_MISC:
    case TV_CHEST:
        break;
    case TV_SLING_AMMO:
    case TV_BOLT:
    case TV_ARROW:
        (void)sprintf(damstr, " (%dd%d)", inventory_p->damage[0],
                      inventory_p->damage[1]);
        break;
    case TV_LIGHT:
        p1_use = LIGHT;
        break;
    case TV_SPIKE:
        break;
    case TV_BOW:
        if (inventory_p->p1 == 1 || inventory_p->p1 == 2)
            tmp = 2;
        else if (inventory_p->p1 == 3 || inventory_p->p1 == 5)
            tmp = 3;
        else if (inventory_p->p1 == 4 || inventory_p->p1 == 6)
            tmp = 4;
        else
            tmp = -1;
        (void)sprintf(damstr, " (x%d)", tmp);
        break;
    case TV_HAFTED:
    case TV_POLEARM:
    case TV_SWORD:
        (void)sprintf(damstr, " (%dd%d)", inventory_p->damage[0],
                      inventory_p->damage[1]);
        p1_use = FLAGS;
        break;
    case TV_DIGGING:
        p1_use = Z_PLUSSES;
        (void)sprintf(damstr, " (%dd%d)", inventory_p->damage[0],
                      inventory_p->damage[1]);
        break;
    case TV_BOOTS:
    case TV_GLOVES:
    case TV_CLOAK:
    case TV_HELM:
    case TV_SHIELD:
    case TV_HARD_ARMOR:
    case TV_SOFT_ARMOR:
        break;
    case TV_AMULET:
        if (modify) {
            basenm = "& %s Amulet";
            modstr = amulets[indexx];
        } else {
            basenm = "& Amulet";
            append_name = TRUE;
        }
        p1_use = PLUSSES;
        break;
    case TV_RING:
        if (modify) {
            basenm = "& %s Ring";
            modstr = rocks[indexx];
        } else {
            basenm = "& Ring";
            append_name = TRUE;
        }
        p1_use = PLUSSES;
        break;
    case TV_STAFF:
        if (modify) {
            basenm = "& %s Staff";
            modstr = woods[indexx];
        } else {
            basenm = "& Staff";
            append_name = TRUE;
        }
        p1_use = CHARGES;
        break;
    case TV_WAND:
        if (modify) {
            basenm = "& %s Wand";
            modstr = metals[indexx];
        } else {
            basenm = "& Wand";
            append_name = TRUE;
        }
        p1_use = CHARGES;
        break;
    case TV_SCROLL1:
    case TV_SCROLL2:
        if (modify) {
            basenm = "& Scroll~ titled \"%s\"";
            modstr = titles[indexx];
        } else {
            basenm = "& Scroll~";
            append_name = TRUE;
        }
        break;
    case TV_POTION1:
    case TV_POTION2:
        if (modify) {
            basenm = "& %s Potion~";
            modstr = colors[indexx];
        } else {
            basenm = "& Potion~";
            append_name = TRUE;
        }
        break;
    case TV_FLASK:
        break;
    case TV_FOOD:
        if (modify) {
            if (indexx <= 15)
                basenm = "& %s Mushroom~";
            else if (indexx <= 20)
                basenm = "& Hairy %s Mold~";
            if (indexx <= 20)
                modstr = mushrooms[indexx];
        } else {
            append_name = TRUE;
            if (indexx <= 15)
                basenm = "& Mushroom~";
            else if (indexx <= 20)
                basenm = "& Hairy Mold~";
            else
                /* Ordinary food does not have a name appended.  */
                append_name = FALSE;
        }
        break;
    case TV_MAGIC_BOOK:
        modstr = basenm;
        basenm = "& Book~ of Magic Spells %s";
        break;
    case TV_PRAYER_BOOK:
        modstr = basenm;
        basenm = "& Holy Book~ of Prayers %s";
        break;
    case TV_OPEN_DOOR:
    case TV_CLOSED_DOOR:
    case TV_SECRET_DOOR:
    case TV_RUBBLE:
        break;
    case TV_GOLD:
    case TV_INVIS_TRAP:
    case TV_VIS_TRAP:
    case TV_UP_STAIR:
    case TV_DOWN_STAIR:
        (void)strcpy(out_val, object_list[inventory_p->index].name);
        (void)strcat(out_val, ".");
        return;
    case TV_STORE_DOOR:
        (void)sprintf(out_val, "the entrance to the %s.",
                      object_list[inventory_p->index].name);
        return;
    default:
        (void)strcpy(out_val, "Error in objdes()");
        return;
    }
    if (modstr != CNIL)
        (void)sprintf(tmp_val, basenm, modstr);
    else
        (void)strcpy(tmp_val, basenm);
    if (append_name) {
        (void)strcat(tmp_val, " of ");
        (void)strcat(tmp_val, object_list[inventory_p->index].name);
    }
    if (inventory_p->number != 1) {
        insert_str(tmp_val, "ch~", "ches");
        insert_str(tmp_val, "~", "s");
    } else
        insert_str(tmp_val, "~", CNIL);
    if (!pref) {
        if (!strncmp("some", tmp_val, 4))
            (void)strcpy(out_val, &tmp_val[5]);
        else if (tmp_val[0] == '&')
            /* eliminate the '& ' at the beginning */
            (void)strcpy(out_val, &tmp_val[2]);
        else
            (void)strcpy(out_val, tmp_val);
    } else {
        if (inventory_p->name2 != SN_NULL && known2_p(inventory_p)) {
            (void)strcat(tmp_val, " ");
            (void)strcat(tmp_val, special_names[inventory_p->name2]);
        }
        if (damstr[0] != '\0')
            (void)strcat(tmp_val, damstr);
        if (known2_p(inventory_p)) {
            /* originally used %+d, but several machines don't support it */
            if (inventory_p->ident & ID_SHOW_HITDAM)
                (void)sprintf(tmp_str, " (%c%d,%c%d)",
                              (inventory_p->tohit < 0) ? '-' : '+',
                              abs(inventory_p->tohit),
                              (inventory_p->todam < 0) ? '-' : '+',
                              abs(inventory_p->todam));
            else if (inventory_p->tohit != 0)
                (void)sprintf(tmp_str, " (%c%d)",
                              (inventory_p->tohit < 0) ? '-' : '+',
                              abs(inventory_p->tohit));
            else if (inventory_p->todam != 0)
                (void)sprintf(tmp_str, " (%c%d)",
                              (inventory_p->todam < 0) ? '-' : '+',
                              abs(inventory_p->todam));
            else
                tmp_str[0] = '\0';
            (void)strcat(tmp_val, tmp_str);
        }
        /* Crowns have a zero base AC, so make a special test for them. */
        if (inventory_p->ac != 0 || (inventory_p->item_category == TV_HELM)) {
            (void)sprintf(tmp_str, " [%d", inventory_p->ac);
            (void)strcat(tmp_val, tmp_str);
            if (known2_p(inventory_p)) {
                /* originally used %+d, but several machines don't support it */
                (void)sprintf(tmp_str, ",%c%d",
                              (inventory_p->toac < 0) ? '-' : '+',
                              abs(inventory_p->toac));
                (void)strcat(tmp_val, tmp_str);
            }
            (void)strcat(tmp_val, "]");
        } else if ((inventory_p->toac != 0) && known2_p(inventory_p)) {
            /* originally used %+d, but several machines don't support it */
            (void)sprintf(tmp_str, " [%c%d]",
                          (inventory_p->toac < 0) ? '-' : '+',
                          abs(inventory_p->toac));
            (void)strcat(tmp_val, tmp_str);
        }

        /* override defaults, check for p1 flags in the ident field */
        if (inventory_p->ident & ID_NOSHOW_P1)
            p1_use = IGNORED;
        else if (inventory_p->ident & ID_SHOW_P1)
            p1_use = Z_PLUSSES;
        tmp_str[0] = '\0';
        if (p1_use == LIGHT)
            (void)sprintf(tmp_str, " with %d turns of light", inventory_p->p1);
        else if (p1_use == IGNORED)
            ;
        else if (known2_p(inventory_p)) {
            if (p1_use == Z_PLUSSES)
                /* originally used %+d, but several machines don't support it */
                (void)sprintf(tmp_str, " (%c%d)",
                              (inventory_p->p1 < 0) ? '-' : '+',
                              abs(inventory_p->p1));
            else if (p1_use == CHARGES)
                (void)sprintf(tmp_str, " (%d charges)", inventory_p->p1);
            else if (inventory_p->p1 != 0) {
                if (p1_use == PLUSSES)
                    (void)sprintf(tmp_str, " (%c%d)",
                                  (inventory_p->p1 < 0) ? '-' : '+',
                                  abs(inventory_p->p1));
                else if (p1_use == FLAGS) {
                    if (inventory_p->flags & TR_STR)
                        (void)sprintf(tmp_str, " (%c%d to STR)",
                                      (inventory_p->p1 < 0) ? '-' : '+',
                                      abs(inventory_p->p1));
                    else if (inventory_p->flags & TR_STEALTH)
                        (void)sprintf(tmp_str, " (%c%d to stealth)",
                                      (inventory_p->p1 < 0) ? '-' : '+',
                                      abs(inventory_p->p1));
                }
            }
        }
        (void)strcat(tmp_val, tmp_str);

        /* ampersand is always the first character */
        if (tmp_val[0] == '&') {
            /* use &tmp_val[1], so that & does not appear in output */
            if (inventory_p->number > 1)
                (void)sprintf(out_val, "%d%s", (int)inventory_p->number,
                              &tmp_val[1]);
            else if (inventory_p->number < 1)
                (void)sprintf(out_val, "%s%s", "no more", &tmp_val[1]);
            else if (is_a_vowel(tmp_val[2]))
                (void)sprintf(out_val, "an%s", &tmp_val[1]);
            else
                (void)sprintf(out_val, "a%s", &tmp_val[1]);
        }
        /* handle 'no more' case specially */
        else if (inventory_p->number < 1) {
            /* check for "some" at start */
            if (!strncmp("some", tmp_val, 4))
                (void)sprintf(out_val, "no more %s", &tmp_val[5]);
            /* here if no article */
            else
                (void)sprintf(out_val, "no more %s", tmp_val);
        } else
            (void)strcpy(out_val, tmp_val);

        tmp_str[0] = '\0';
        if ((indexx = object_offset(inventory_p)) >= 0) {
            indexx = (indexx <<= 6) + (inventory_p->item_subcategory &
                                       (ITEM_SINGLE_STACK_MIN - 1));
            /* don't print tried string for store bought items */
            if ((object_ident[indexx] & OD_TRIED) &&
                !store_bought_p(inventory_p))
                (void)strcat(tmp_str, "tried ");
        }
        if (inventory_p->ident & (ID_MAGIK | ID_EMPTY | ID_DAMD)) {
            if (inventory_p->ident & ID_MAGIK)
                (void)strcat(tmp_str, "magik ");
            if (inventory_p->ident & ID_EMPTY)
                (void)strcat(tmp_str, "empty ");
            if (inventory_p->ident & ID_DAMD)
                (void)strcat(tmp_str, "damned ");
        }
        if (inventory_p->inscrip[0] != '\0')
            (void)strcat(tmp_str, inventory_p->inscrip);
        else if ((indexx = strlen(tmp_str)) > 0)
            /* remove the extra blank at the end */
            tmp_str[indexx - 1] = '\0';
        if (tmp_str[0]) {
            (void)sprintf(tmp_val, " {%s}", tmp_str);
            (void)strcat(out_val, tmp_val);
        }
        (void)strcat(out_val, ".");
    }
}

void invcopy(inven_type *to, int from_index) {
    treasure_type *from = &object_list[from_index];
    *to = (inven_type){.index = from_index,
                       .name2 = SN_NULL,
                       .inscrip = {'\0'},
                       .flags = from->flags,
                       .item_category = from->tval,
                       .tchar = from->tchar,
                       .p1 = from->p1,
                       .cost = from->cost,
                       .item_subcategory = from->subval,
                       .number = from->number,
                       .weight = from->weight,
                       .tohit = from->tohit,
                       .todam = from->todam,
                       .ac = from->ac,
                       .toac = from->toac,
                       .damage = {from->damage[0], from->damage[1]},
                       .level = from->level,
                       .ident = 0};
}

/* Describe number of remaining charges.		-RAK-	*/
void desc_charges(item_val) int item_val;
{
    int rem_num;
    vtype out_val;

    if (known2_p(&inventory[item_val])) {
        rem_num = inventory[item_val].p1;
        (void)sprintf(out_val, "You have %d charges remaining.", rem_num);
        msg_print(out_val);
    }
}

/* Describe amount of item remaining.			-RAK-	*/
void desc_remain(item_val) int item_val;
{
    bigvtype out_val, tmp_str;
    inven_type *inventory_p;

    inventory_p = &inventory[item_val];
    inventory_p->number--;
    objdes(tmp_str, inventory_p, TRUE);
    inventory_p->number++;
    /* the string already has a dot at the end. */
    (void)sprintf(out_val, "You have %s", tmp_str);
    msg_print(out_val);
}

