#include <stdio.h>

#ifdef USG
#include <string.h>
#else
#include <strings.h>
#endif

/* Scrolls for the reading				-RAK-	*/
void read_scroll() {
    u32i i;
    int j, k, item_val, y, x;
    int tmp[6], flag, used_up;
    bigvtype out_val, tmp_str;
    int ident, l;
    inven_type *inventory_p;
    struct misc *m_ptr;
#ifdef ATARIST_MWC
    int32u holder = TR_CURSED;
#endif

    free_turn_flag = TRUE;
    if (py.flags.blind > 0)
        msg_print("You can't see to read the scroll.");
    else if (no_light())
        msg_print("You have no light to read by.");
    else if (py.flags.confused > 0)
        msg_print("You are too confused to read a scroll.");
    else if (inventory_counter == 0)
        msg_print("You are not carrying anything!");
    else if (!find_range(TV_SCROLL1, TV_SCROLL2, &j, &k))
        msg_print("You are not carrying any scrolls!");
    else if (get_item(&item_val, "Read which scroll?", j, k, CNIL, CNIL)) {
        inventory_p = &inventory[item_val];
        free_turn_flag = FALSE;
        used_up = TRUE;
        i = inventory_p->flags;
        ident = FALSE;

        while (i != 0) {
            j = bit_pos(&i) + 1;
            if (inventory_p->item_category == TV_SCROLL2)
                j += 32;

            /* Scrolls.			*/
            switch (j) {
            case 1:
                inventory_p = &inventory[INVEN_WIELD];
                if (inventory_p->item_category != TV_NOTHING) {
                    objdes(tmp_str, inventory_p, FALSE);
                    (void)sprintf(out_val, "Your %s glows faintly!", tmp_str);
                    msg_print(out_val);
                    if (enchant(&inventory_p->tohit, 10)) {
#ifdef ATARIST_MWC
                        inventory_p->flags &= ~holder;
#else
                        inventory_p->flags &= ~TR_CURSED;
#endif
                        calc_bonuses();
                    } else
                        msg_print("The enchantment fails.");
                    ident = TRUE;
                }
                break;
            case 2:
                inventory_p = &inventory[INVEN_WIELD];
                if (inventory_p->item_category != TV_NOTHING) {
                    objdes(tmp_str, inventory_p, FALSE);
                    (void)sprintf(out_val, "Your %s glows faintly!", tmp_str);
                    msg_print(out_val);
                    if ((inventory_p->item_category >= TV_HAFTED) &&
                        (inventory_p->item_category <= TV_DIGGING))
                        j = inventory_p->damage[0] * inventory_p->damage[1];
                    else /* Bows' and arrows' enchantments should not be limited
                            by their low base damages */
                        j = 10;
                    if (enchant(&inventory_p->todam, j)) {
#ifdef ATARIST_MWC
                        inventory_p->flags &= ~holder;
#else
                        inventory_p->flags &= ~TR_CURSED;
#endif
                        calc_bonuses();
                    } else
                        msg_print("The enchantment fails.");
                    ident = TRUE;
                }
                break;
            case 3:
                k = 0;
                l = 0;
                if (inventory[INVEN_BODY].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_BODY;
                if (inventory[INVEN_ARM].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_ARM;
                if (inventory[INVEN_OUTER].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_OUTER;
                if (inventory[INVEN_HANDS].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_HANDS;
                if (inventory[INVEN_HEAD].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_HEAD;
                /* also enchant boots */
                if (inventory[INVEN_FEET].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_FEET;

                if (k > 0)
                    l = tmp[randint(k) - 1];
#ifdef ATARIST_MWC
                if (holder & inventory[INVEN_BODY].flags)
                    l = INVEN_BODY;
                else if (holder & inventory[INVEN_ARM].flags)
                    l = INVEN_ARM;
                else if (holder & inventory[INVEN_OUTER].flags)
                    l = INVEN_OUTER;
                else if (holder & inventory[INVEN_HEAD].flags)
                    l = INVEN_HEAD;
                else if (holder & inventory[INVEN_HANDS].flags)
                    l = INVEN_HANDS;
                else if (holder & inventory[INVEN_FEET].flags)
                    l = INVEN_FEET;
#else
                if (TR_CURSED & inventory[INVEN_BODY].flags)
                    l = INVEN_BODY;
                else if (TR_CURSED & inventory[INVEN_ARM].flags)
                    l = INVEN_ARM;
                else if (TR_CURSED & inventory[INVEN_OUTER].flags)
                    l = INVEN_OUTER;
                else if (TR_CURSED & inventory[INVEN_HEAD].flags)
                    l = INVEN_HEAD;
                else if (TR_CURSED & inventory[INVEN_HANDS].flags)
                    l = INVEN_HANDS;
                else if (TR_CURSED & inventory[INVEN_FEET].flags)
                    l = INVEN_FEET;
#endif

                if (l > 0) {
                    inventory_p = &inventory[l];
                    objdes(tmp_str, inventory_p, FALSE);
                    (void)sprintf(out_val, "Your %s glows faintly!", tmp_str);
                    msg_print(out_val);
                    if (enchant(&inventory_p->toac, 10)) {
#ifdef ATARIST_MWC
                        inventory_p->flags &= ~holder;
#else
                        inventory_p->flags &= ~TR_CURSED;
#endif
                        calc_bonuses();
                    } else
                        msg_print("The enchantment fails.");
                    ident = TRUE;
                }
                break;
            case 4:
                msg_print("This is an identify scroll.");
                ident = TRUE;
                used_up = ident_spell();

                /* The identify may merge objects, causing the identify scroll
                   to move to a different place.	Check for that here.  It
                   can move arbitrarily far if an identify scroll was used on
                   another identify scroll, but it always moves down. */
                while (inventory_p->item_category != TV_SCROLL1 ||
                       inventory_p->flags != 0x00000008) {
                    item_val--;
                    inventory_p = &inventory[item_val];
                }
                break;
            case 5:
                if (remove_curse()) {
                    msg_print("You feel as if someone is watching over you.");
                    ident = TRUE;
                }
                break;
            case 6:
                ident = light_area(char_row, char_col);
                break;
            case 7:
                for (k = 0; k < randint(3); k++) {
                    y = char_row;
                    x = char_col;
                    ident |= summon_monster(&y, &x, FALSE);
                }
                break;
            case 8:
                teleport(10);
                ident = TRUE;
                break;
            case 9:
                teleport(100);
                ident = TRUE;
                break;
            case 10:
                dun_level += (-3) + 2 * randint(2);
                if (dun_level < 1)
                    dun_level = 1;
                new_level_flag = TRUE;
                ident = TRUE;
                break;
            case 11:
                if (py.flags.confuse_monster == 0) {
                    msg_print("Your hands begin to glow.");
                    py.flags.confuse_monster = TRUE;
                    ident = TRUE;
                }
                break;
            case 12:
                ident = TRUE;
                map_area();
                break;
            case 13:
                ident = sleep_monsters1(char_row, char_col);
                break;
            case 14:
                ident = TRUE;
                warding_glyph();
                break;
            case 15:
                ident = detect_treasure();
                break;
            case 16:
                ident = detect_object();
                break;
            case 17:
                ident = detect_trap();
                break;
            case 18:
                ident = detect_sdoor();
                break;
            case 19:
                msg_print("This is a mass genocide scroll.");
                (void)mass_genocide();
                ident = TRUE;
                break;
            case 20:
                ident = detect_invisible();
                break;
            case 21:
                msg_print("There is a high pitched humming noise.");
                (void)aggravate_monster(20);
                ident = TRUE;
                break;
            case 22:
                ident = trap_creation();
                break;
            case 23:
                ident = td_destroy();
                break;
            case 24:
                ident = door_creation();
                break;
            case 25:
                msg_print("This is a Recharge-Item scroll.");
                ident = TRUE;
                used_up = recharge(60);
                break;
            case 26:
                msg_print("This is a genocide scroll.");
                (void)genocide();
                ident = TRUE;
                break;
            case 27:
                ident = unlight_area(char_row, char_col);
                break;
            case 28:
                ident = protect_evil();
                break;
            case 29:
                ident = TRUE;
                create_food();
                break;
            case 30:
                ident = dispel_creature(CD_UNDEAD, 60);
                break;
            case 33:
                inventory_p = &inventory[INVEN_WIELD];
                if (inventory_p->item_category != TV_NOTHING) {
                    objdes(tmp_str, inventory_p, FALSE);
                    (void)sprintf(out_val, "Your %s glows brightly!", tmp_str);
                    msg_print(out_val);
                    flag = FALSE;
                    for (k = 0; k < randint(2); k++)
                        if (enchant(&inventory_p->tohit, 10))
                            flag = TRUE;
                    if ((inventory_p->item_category >= TV_HAFTED) &&
                        (inventory_p->item_category <= TV_DIGGING))
                        j = inventory_p->damage[0] * inventory_p->damage[1];
                    else /* Bows' and arrows' enchantments should not be limited
                            by their low base damages */
                        j = 10;
                    for (k = 0; k < randint(2); k++)
                        if (enchant(&inventory_p->todam, j))
                            flag = TRUE;
                    if (flag) {
#ifdef ATARIST_MWC
                        inventory_p->flags &= ~holder;
#else
                        inventory_p->flags &= ~TR_CURSED;
#endif
                        calc_bonuses();
                    } else
                        msg_print("The enchantment fails.");
                    ident = TRUE;
                }
                break;
            case 34:
                inventory_p = &inventory[INVEN_WIELD];
                if (inventory_p->item_category != TV_NOTHING) {
                    objdes(tmp_str, inventory_p, FALSE);
                    (void)sprintf(out_val, "Your %s glows black, fades.",
                                  tmp_str);
                    msg_print(out_val);
                    unmagic_name(inventory_p);
                    inventory_p->tohit = -randint(5) - randint(5);
                    inventory_p->todam = -randint(5) - randint(5);
                    inventory_p->toac = 0;
                    /* Must call py_bonuses() before set (clear) flags, and
                       must call calc_bonuses() after set (clear) flags, so that
                       all attributes will be properly turned off. */
                    py_bonuses(inventory_p, -1);
                    inventory_p->flags = TR_CURSED;
                    calc_bonuses();
                    ident = TRUE;
                }
                break;
            case 35:
                k = 0;
                l = 0;
                if (inventory[INVEN_BODY].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_BODY;
                if (inventory[INVEN_ARM].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_ARM;
                if (inventory[INVEN_OUTER].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_OUTER;
                if (inventory[INVEN_HANDS].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_HANDS;
                if (inventory[INVEN_HEAD].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_HEAD;
                /* also enchant boots */
                if (inventory[INVEN_FEET].item_category != TV_NOTHING)
                    tmp[k++] = INVEN_FEET;

                if (k > 0)
                    l = tmp[randint(k) - 1];
#ifdef ATARIST_MWC
                if (holder & inventory[INVEN_BODY].flags)
                    l = INVEN_BODY;
                else if (holder & inventory[INVEN_ARM].flags)
                    l = INVEN_ARM;
                else if (holder & inventory[INVEN_OUTER].flags)
                    l = INVEN_OUTER;
                else if (holder & inventory[INVEN_HEAD].flags)
                    l = INVEN_HEAD;
                else if (holder & inventory[INVEN_HANDS].flags)
                    l = INVEN_HANDS;
                else if (holder & inventory[INVEN_FEET].flags)
                    l = INVEN_FEET;
#else
                if (TR_CURSED & inventory[INVEN_BODY].flags)
                    l = INVEN_BODY;
                else if (TR_CURSED & inventory[INVEN_ARM].flags)
                    l = INVEN_ARM;
                else if (TR_CURSED & inventory[INVEN_OUTER].flags)
                    l = INVEN_OUTER;
                else if (TR_CURSED & inventory[INVEN_HEAD].flags)
                    l = INVEN_HEAD;
                else if (TR_CURSED & inventory[INVEN_HANDS].flags)
                    l = INVEN_HANDS;
                else if (TR_CURSED & inventory[INVEN_FEET].flags)
                    l = INVEN_FEET;
#endif

                if (l > 0) {
                    inventory_p = &inventory[l];
                    objdes(tmp_str, inventory_p, FALSE);
                    (void)sprintf(out_val, "Your %s glows brightly!", tmp_str);
                    msg_print(out_val);
                    flag = FALSE;
                    for (k = 0; k < randint(2) + 1; k++)
                        if (enchant(&inventory_p->toac, 10))
                            flag = TRUE;
                    if (flag) {
#ifdef ATARIST_MWC
                        inventory_p->flags &= ~holder;
#else
                        inventory_p->flags &= ~TR_CURSED;
#endif
                        calc_bonuses();
                    } else
                        msg_print("The enchantment fails.");
                    ident = TRUE;
                }
                break;
            case 36:
                if ((inventory[INVEN_BODY].item_category != TV_NOTHING) &&
                    (randint(4) == 1))
                    k = INVEN_BODY;
                else if ((inventory[INVEN_ARM].item_category != TV_NOTHING) &&
                         (randint(3) == 1))
                    k = INVEN_ARM;
                else if ((inventory[INVEN_OUTER].item_category != TV_NOTHING) &&
                         (randint(3) == 1))
                    k = INVEN_OUTER;
                else if ((inventory[INVEN_HEAD].item_category != TV_NOTHING) &&
                         (randint(3) == 1))
                    k = INVEN_HEAD;
                else if ((inventory[INVEN_HANDS].item_category != TV_NOTHING) &&
                         (randint(3) == 1))
                    k = INVEN_HANDS;
                else if ((inventory[INVEN_FEET].item_category != TV_NOTHING) &&
                         (randint(3) == 1))
                    k = INVEN_FEET;
                else if (inventory[INVEN_BODY].item_category != TV_NOTHING)
                    k = INVEN_BODY;
                else if (inventory[INVEN_ARM].item_category != TV_NOTHING)
                    k = INVEN_ARM;
                else if (inventory[INVEN_OUTER].item_category != TV_NOTHING)
                    k = INVEN_OUTER;
                else if (inventory[INVEN_HEAD].item_category != TV_NOTHING)
                    k = INVEN_HEAD;
                else if (inventory[INVEN_HANDS].item_category != TV_NOTHING)
                    k = INVEN_HANDS;
                else if (inventory[INVEN_FEET].item_category != TV_NOTHING)
                    k = INVEN_FEET;
                else
                    k = 0;

                if (k > 0) {
                    inventory_p = &inventory[k];
                    objdes(tmp_str, inventory_p, FALSE);
                    (void)sprintf(out_val, "Your %s glows black, fades.",
                                  tmp_str);
                    msg_print(out_val);
                    unmagic_name(inventory_p);
                    inventory_p->flags = TR_CURSED;
                    inventory_p->tohit = 0;
                    inventory_p->todam = 0;
                    inventory_p->toac = -randint(5) - randint(5);
                    calc_bonuses();
                    ident = TRUE;
                }
                break;
            case 37:
                ident = FALSE;
                for (k = 0; k < randint(3); k++) {
                    y = char_row;
                    x = char_col;
                    ident |= summon_undead(&y, &x);
                }
                break;
            case 38:
                ident = TRUE;
                bless(randint(12) + 6);
                break;
            case 39:
                ident = TRUE;
                bless(randint(24) + 12);
                break;
            case 40:
                ident = TRUE;
                bless(randint(48) + 24);
                break;
            case 41:
                ident = TRUE;
                if (py.flags.word_recall == 0)
                    py.flags.word_recall = 25 + randint(30);
                msg_print("The air about you becomes charged.");
                break;
            case 42:
                destroy_area(char_row, char_col);
                ident = TRUE;
                break;
            default:
                msg_print("Internal error in scroll()");
                break;
            }
            /* End of Scrolls.			       */
        }
        inventory_p = &inventory[item_val];
        if (ident) {
            if (!known1_p(inventory_p)) {
                m_ptr = &py.misc;
                /* round half-way case up */
                m_ptr->exp +=
                    (inventory_p->level + (m_ptr->level >> 1)) / m_ptr->level;
                prt_experience();

                identify(&item_val);
                inventory_p = &inventory[item_val];
            }
        } else if (!known1_p(inventory_p))
            sample(inventory_p);
        if (used_up) {
            desc_remain(item_val);
            inven_destroy(item_val);
        }
    }
}

