/* Increase or decrease a creatures speed		-RAK-	*/
/* NOTE: cannot slow a winning creature (BALROG)		 */
int speed_monster(dir, y, x, spd)
int dir, y, x, spd;
{
    int flag, dist, speed;
    cave_type *c_ptr;
    monster_type *m_ptr;
    creature_type *r_ptr;
    vtype out_val, m_name;

    speed = FALSE;
    flag = FALSE;
    dist = 0;
    do {
        (void)mmove(dir, &y, &x);
        dist++;
        c_ptr = &cave[y][x];
        if ((dist > OBJ_BOLT_RANGE) || c_ptr->fval >= MIN_CLOSED_SPACE)
            flag = TRUE;
        else if (c_ptr->cptr > 1) {
            flag = TRUE;
            m_ptr = &m_list[c_ptr->cptr];
            r_ptr = &c_list[m_ptr->mptr];
            monster_name(m_name, m_ptr, r_ptr);
            if (spd > 0) {
                m_ptr->cspeed += spd;
                m_ptr->csleep = 0;
                (void)sprintf(out_val, "%s starts moving faster.", m_name);
                msg_print(out_val);
                speed = TRUE;
            } else if (randint(MAX_MONS_LEVEL) > r_ptr->level) {
                m_ptr->cspeed += spd;
                m_ptr->csleep = 0;
                (void)sprintf(out_val, "%s starts moving slower.", m_name);
                msg_print(out_val);
                speed = TRUE;
            } else {
                m_ptr->csleep = 0;
                (void)sprintf(out_val, "%s is unaffected.", m_name);
                msg_print(out_val);
            }
        }
    } while (!flag);
    return (speed);
}

/* Confuse a creature					-RAK-	*/
int confuse_monster(dir, y, x)
int dir, y, x;
{
    int flag, dist, confuse;
    cave_type *c_ptr;
    monster_type *m_ptr;
    creature_type *r_ptr;
    vtype out_val, m_name;

    confuse = FALSE;
    flag = FALSE;
    dist = 0;
    do {
        (void)mmove(dir, &y, &x);
        dist++;
        c_ptr = &cave[y][x];
        if ((dist > OBJ_BOLT_RANGE) || c_ptr->fval >= MIN_CLOSED_SPACE)
            flag = TRUE;
        else if (c_ptr->cptr > 1) {
            m_ptr = &m_list[c_ptr->cptr];
            r_ptr = &c_list[m_ptr->mptr];
            monster_name(m_name, m_ptr, r_ptr);
            flag = TRUE;
            if ((randint(MAX_MONS_LEVEL) < r_ptr->level) ||
                (CD_NO_SLEEP & r_ptr->cdefense)) {
                if (m_ptr->ml && (r_ptr->cdefense & CD_NO_SLEEP))
                    c_recall[m_ptr->mptr].r_cdefense |= CD_NO_SLEEP;
                /* Monsters which resisted the attack should wake up.
                   Monsters with innate resistence ignore the attack.  */
                if (!(CD_NO_SLEEP & r_ptr->cdefense))
                    m_ptr->csleep = 0;
                (void)sprintf(out_val, "%s is unaffected.", m_name);
                msg_print(out_val);
            } else {
                if (m_ptr->confused)
                    m_ptr->confused += 3;
                else
                    m_ptr->confused = 2 + randint(16);
                confuse = TRUE;
                m_ptr->csleep = 0;
                (void)sprintf(out_val, "%s appears confused.", m_name);
                msg_print(out_val);
            }
        }
    } while (!flag);
    return (confuse);
}

