/* Change players hit points in some manner		-RAK-	*/
int hp_player(num)
int num;
{
    int res;
    struct misc *m_ptr;

    res = FALSE;
    m_ptr = &py.misc;
    if (m_ptr->chp < m_ptr->mhp) {
        m_ptr->chp += num;
        if (m_ptr->chp > m_ptr->mhp) {
            m_ptr->chp = m_ptr->mhp;
            m_ptr->chp_frac = 0;
        }
        prt_chp();

        num = num / 5;
        if (num < 3) {
            if (num == 0)
                msg_print("You feel a little better.");
            else
                msg_print("You feel better.");
        } else {
            if (num < 7)
                msg_print("You feel much better.");
            else
                msg_print("You feel very good.");
        }
        res = TRUE;
    }
    return (res);
}

