/* Lose experience					-RAK-	*/
void lose_exp(amount) int32 amount;
{
    int i;
    struct misc *m_ptr;
    class_type *c_ptr;

    m_ptr = &py.misc;
    if (amount > m_ptr->exp)
        m_ptr->exp = 0;
    else
        m_ptr->exp -= amount;
    prt_experience();

    i = 0;
    while ((player_exp[i] * m_ptr->expfact / 100) <= m_ptr->exp)
        i++;
    /* increment i once more, because level 1 exp is stored in player_exp[0] */
    i++;

    if (m_ptr->level != i) {
        m_ptr->level = i;

        calc_hitpoints();
        c_ptr = &class[m_ptr->pclass];
        if (c_ptr->spell == MAGE) {
            calc_spells(A_INT);
            calc_mana(A_INT);
        } else if (c_ptr->spell == PRIEST) {
            calc_spells(A_WIS);
            calc_mana(A_WIS);
        }
        prt_level();
        prt_title();
    }
}

