#ifdef USG
#ifndef ATARIST_MWC
#include <string.h>
#endif
#else
#include <strings.h>
#endif

/* Wands for the aiming.				*/
void aim() {
    u32i i;
    int l, ident;
    int item_val, j, k, chance, dir;
    inven_type *inventory_p;
    struct misc *m_ptr;

    free_turn_flag = TRUE;
    if (inventory_counter == 0)
        msg_print("But you are not carrying anything.");
    else if (!find_range(TV_WAND, TV_NEVER, &j, &k))
        msg_print("You are not carrying any wands.");
    else if (get_item(&item_val, "Aim which wand?", j, k, CNIL, CNIL)) {
        inventory_p = &inventory[item_val];
        free_turn_flag = FALSE;
        if (get_dir(CNIL, &dir)) {
            if (py.flags.confused > 0) {
                msg_print("You are confused.");
                do {
                    dir = randint(9);
                } while (dir == 5);
            }
            ident = FALSE;
            m_ptr = &py.misc;
            chance =
                m_ptr->save + get_mana_multiplier(A_INT) -
                (int)inventory_p->level +
                (class_level_adj[m_ptr->pclass][CLA_DEVICE] * m_ptr->level / 3);
            if (py.flags.confused > 0)
                chance = chance / 2;
            if ((chance < USE_DEVICE) &&
                (randint(USE_DEVICE - chance + 1) == 1))
                chance = USE_DEVICE; /* Give everyone a slight chance */
            if (chance <= 0)
                chance = 1;
            if (randint(chance) < USE_DEVICE)
                msg_print("You failed to use the wand properly.");
            else if (inventory_p->p1 > 0) {
                i = inventory_p->flags;
                (inventory_p->p1)--;
                while (i != 0) {
                    j = bit_pos(&i) + 1;
                    k = char_row;
                    l = char_col;
                    /* Wands			 */
                    switch (j) {
                    case 1:
                        msg_print("A line of blue shimmering light appears.");
                        light_line(dir, char_row, char_col);
                        ident = TRUE;
                        break;
                    case 2:
                        fire_bolt(GF_LIGHTNING, dir, k, l, damroll(4, 8),
                                  spell_names[8]);
                        ident = TRUE;
                        break;
                    case 3:
                        fire_bolt(GF_FROST, dir, k, l, damroll(6, 8),
                                  spell_names[14]);
                        ident = TRUE;
                        break;
                    case 4:
                        fire_bolt(GF_FIRE, dir, k, l, damroll(9, 8),
                                  spell_names[22]);
                        ident = TRUE;
                        break;
                    case 5:
                        ident = wall_to_mud(dir, k, l);
                        break;
                    case 6:
                        ident = poly_monster(dir, k, l);
                        break;
                    case 7:
                        ident = hp_monster(dir, k, l, -damroll(4, 6));
                        break;
                    case 8:
                        ident = speed_monster(dir, k, l, 1);
                        break;
                    case 9:
                        ident = speed_monster(dir, k, l, -1);
                        break;
                    case 10:
                        ident = confuse_monster(dir, k, l);
                        break;
                    case 11:
                        ident = sleep_monster(dir, k, l);
                        break;
                    case 12:
                        ident = drain_life(dir, k, l);
                        break;
                    case 13:
                        ident = td_destroy2(dir, k, l);
                        break;
                    case 14:
                        fire_bolt(GF_MAGIC_MISSILE, dir, k, l, damroll(2, 6),
                                  spell_names[0]);
                        ident = TRUE;
                        break;
                    case 15:
                        ident = build_wall(dir, k, l);
                        break;
                    case 16:
                        ident = clone_monster(dir, k, l);
                        break;
                    case 17:
                        ident = teleport_monster(dir, k, l);
                        break;
                    case 18:
                        ident = disarm_all(dir, k, l);
                        break;
                    case 19:
                        fire_ball(GF_LIGHTNING, dir, k, l, 32,
                                  "Lightning Ball");
                        ident = TRUE;
                        break;
                    case 20:
                        fire_ball(GF_FROST, dir, k, l, 48, "Cold Ball");
                        ident = TRUE;
                        break;
                    case 21:
                        fire_ball(GF_FIRE, dir, k, l, 72, spell_names[28]);
                        ident = TRUE;
                        break;
                    case 22:
                        fire_ball(GF_POISON_GAS, dir, k, l, 12, spell_names[6]);
                        ident = TRUE;
                        break;
                    case 23:
                        fire_ball(GF_ACID, dir, k, l, 60, "Acid Ball");
                        ident = TRUE;
                        break;
                    case 24:
                        i = 1L << (randint(23) - 1);
                        break;
                    default:
                        msg_print("Internal error in wands()");
                        break;
                    }
                    /* End of Wands.		    */
                }
                if (ident) {
                    if (!known1_p(inventory_p)) {
                        m_ptr = &py.misc;
                        /* round half-way case up */
                        m_ptr->exp +=
                            (inventory_p->level + (m_ptr->level >> 1)) /
                            m_ptr->level;
                        prt_experience();

                        identify(&item_val);
                        inventory_p = &inventory[item_val];
                    }
                } else if (!known1_p(inventory_p))
                    sample(inventory_p);
                desc_charges(item_val);
            } else {
                msg_print("The wand has no charges left.");
                if (!known2_p(inventory_p))
                    add_inscribe(inventory_p, ID_EMPTY);
            }
        }
    }
}

