/* Returns the value for any given object		-RAK-	*/
int32 item_value(inventory_p)
inven_type *inventory_p;
{
    int32 value;

    value = inventory_p->cost;
    /* don't purchase known cursed items */
    if (inventory_p->ident & ID_DAMD)
        value = 0;
    else if (((inventory_p->item_category >= TV_BOW) &&
              (inventory_p->item_category <= TV_SWORD)) ||
             ((inventory_p->item_category >= TV_BOOTS) &&
              (inventory_p->item_category <=
               TV_SOFT_ARMOR))) { /* Weapons and armor	*/
        if (!known2_p(inventory_p))
            value = object_list[inventory_p->index].cost;
        else if ((inventory_p->item_category >= TV_BOW) &&
                 (inventory_p->item_category <= TV_SWORD)) {
            if (inventory_p->tohit < 0)
                value = 0;
            else if (inventory_p->todam < 0)
                value = 0;
            else if (inventory_p->toac < 0)
                value = 0;
            else
                value = inventory_p->cost +
                        (inventory_p->tohit + inventory_p->todam +
                         inventory_p->toac) *
                            100;
        } else {
            if (inventory_p->toac < 0)
                value = 0;
            else
                value = inventory_p->cost + inventory_p->toac * 100;
        }
    } else if ((inventory_p->item_category >= TV_SLING_AMMO) &&
               (inventory_p->item_category <=
                TV_SPIKE)) { /* Ammo			*/
        if (!known2_p(inventory_p))
            value = object_list[inventory_p->index].cost;
        else {
            if (inventory_p->tohit < 0)
                value = 0;
            else if (inventory_p->todam < 0)
                value = 0;
            else if (inventory_p->toac < 0)
                value = 0;
            else
                /* use 5, because missiles generally appear in groups of 20,
                   so 20 * 5 == 100, which is comparable to weapon bonus above
                 */
                value = inventory_p->cost +
                        (inventory_p->tohit + inventory_p->todam +
                         inventory_p->toac) *
                            5;
        }
    } else if ((inventory_p->item_category == TV_SCROLL1) ||
               (inventory_p->item_category == TV_SCROLL2) ||
               (inventory_p->item_category == TV_POTION1) ||
               (inventory_p->item_category ==
                TV_POTION2)) { /* Potions, Scrolls, and Food	*/
        if (!known1_p(inventory_p))
            value = 20;
    } else if (inventory_p->item_category == TV_FOOD) {
        if ((inventory_p->item_subcategory <
             (ITEM_SINGLE_STACK_MIN + MAX_MUSH)) &&
            !known1_p(inventory_p))
            value = 1;
    } else if ((inventory_p->item_category == TV_AMULET) ||
               (inventory_p->item_category ==
                TV_RING)) { /* Rings and amulets	*/
        if (!known1_p(inventory_p))
            /* player does not know what type of ring/amulet this is */
            value = 45;
        else if (!known2_p(inventory_p))
            /* player knows what type of ring, but does not know whether it is
               cursed or not, if refuse to buy cursed objects here, then
               player can use this to 'identify' cursed objects */
            value = object_list[inventory_p->index].cost;
    } else if ((inventory_p->item_category == TV_STAFF) ||
               (inventory_p->item_category == TV_WAND)) { /* Wands and staffs*/
        if (!known1_p(inventory_p)) {
            if (inventory_p->item_category == TV_WAND)
                value = 50;
            else
                value = 70;
        } else if (known2_p(inventory_p))
            value =
                inventory_p->cost + (inventory_p->cost / 20) * inventory_p->p1;
    }
    /* picks and shovels */
    else if (inventory_p->item_category == TV_DIGGING) {
        if (!known2_p(inventory_p))
            value = object_list[inventory_p->index].cost;
        else {
            if (inventory_p->p1 < 0)
                value = 0;
            else {
                /* some digging tools start with non-zero p1 values, so only
                   multiply the plusses by 100, make sure result is positive */
                value = inventory_p->cost +
                        (inventory_p->p1 - object_list[inventory_p->index].p1) *
                            100;
                if (value < 0)
                    value = 0;
            }
        }
    }
    /* multiply value by number of items if it is a group stack item */
    if (inventory_p->item_subcategory >
        ITEM_GROUP_MIN) /* do not include torches here */
        value = value * inventory_p->number;
    return (value);
}

/* Asking price for an item				-RAK-	*/
int32 sell_price(snum, max_sell, min_sell, item)
int snum;
int32 *max_sell, *min_sell;
inven_type *item;
{
    int32 i;
    store_type *s_ptr;

    s_ptr = &store[snum];
    i = item_value(item);
    /* check item->cost in case it is cursed, check i in case it is damaged */
    if ((item->cost > 0) && (i > 0)) {
        i = i * rgold_adj[owners[s_ptr->owner].owner_race][py.misc.prace] / 100;
        if (i < 1)
            i = 1;
        *max_sell = i * owners[s_ptr->owner].max_inflate / 100;
        *min_sell = i * owners[s_ptr->owner].min_inflate / 100;
        if (*min_sell > *max_sell)
            *min_sell = *max_sell;
        return (i);
    } else
        /* don't let the item get into the store inventory */
        return (0);
}

/* Check to see if he will be carrying too many objects	-RAK-	*/
int store_check_num(t_ptr, store_num)
inven_type *t_ptr;
int store_num;
{
    int store_check, i;
    store_type *s_ptr;
    inven_type *inventory_p;

    store_check = FALSE;
    s_ptr = &store[store_num];
    if (s_ptr->store_ctr < STORE_INVEN_MAX)
        store_check = TRUE;
    else if (t_ptr->item_subcategory >= ITEM_SINGLE_STACK_MIN)
        for (i = 0; i < s_ptr->store_ctr; i++) {
            inventory_p = &s_ptr->store_inven[i].sitem;
            /* note: items with subval of gte ITEM_SINGLE_STACK_MAX only stack
               if their subvals match */
            if (inventory_p->item_category == t_ptr->item_category &&
                inventory_p->item_subcategory == t_ptr->item_subcategory &&
                ((int)inventory_p->number + (int)t_ptr->number < 256) &&
                (t_ptr->item_subcategory < ITEM_GROUP_MIN ||
                 (inventory_p->p1 == t_ptr->p1)))
                store_check = TRUE;
        }
    return (store_check);
}

/* Insert INVEN_MAX at given location	*/
static void insert_store(store_num, pos, icost, inventory_p) int pos;
int store_num;
int32 icost;
inven_type *inventory_p;
{
    int i;
    store_type *s_ptr;

    s_ptr = &store[store_num];
    for (i = s_ptr->store_ctr - 1; i >= pos; i--)
        s_ptr->store_inven[i + 1] = s_ptr->store_inven[i];
    s_ptr->store_inven[pos].sitem = *inventory_p;
    s_ptr->store_inven[pos].scost = -icost;
    s_ptr->store_ctr++;
}

/* Add the item in INVEN_MAX to stores inventory.	-RAK-	*/
void store_carry(store_num, ipos, t_ptr) int store_num;
int *ipos;
inven_type *t_ptr;
{
    int item_num, item_val, flag;
    int typ, subt;
    int32 icost, dummy;
    inven_type *inventory_p;
    store_type *s_ptr;

    *ipos = -1;
    if (sell_price(store_num, &icost, &dummy, t_ptr) > 0) {
        s_ptr = &store[store_num];
        item_val = 0;
        item_num = t_ptr->number;
        flag = FALSE;
        typ = t_ptr->item_category;
        subt = t_ptr->item_subcategory;
        do {
            inventory_p = &s_ptr->store_inven[item_val].sitem;
            if (typ == inventory_p->item_category) {
                if (subt ==
                        inventory_p
                            ->item_subcategory && /* Adds to other item	*/
                    subt >= ITEM_SINGLE_STACK_MIN &&
                    (subt < ITEM_GROUP_MIN || inventory_p->p1 == t_ptr->p1)) {
                    *ipos = item_val;
                    inventory_p->number += item_num;
                    /* must set new scost for group items, do this only for
                       items strictly greater than group_min, not for torches,
                       this must be recalculated for entire group */
                    if (subt > ITEM_GROUP_MIN) {
                        (void)sell_price(store_num, &icost, &dummy,
                                         inventory_p);
                        s_ptr->store_inven[item_val].scost = -icost;
                    }
                    /* must let group objects (except torches) stack over 24
                       since there may be more than 24 in the group */
                    else if (inventory_p->number > 24)
                        inventory_p->number = 24;
                    flag = TRUE;
                }
            } else if (typ > inventory_p->item_category) { /* Insert into list
                                                            */
                insert_store(store_num, item_val, icost, t_ptr);
                flag = TRUE;
                *ipos = item_val;
            }
            item_val++;
        } while ((item_val < s_ptr->store_ctr) && (!flag));
        if (!flag) /* Becomes last item in list	*/
        {
            insert_store(store_num, (int)s_ptr->store_ctr, icost, t_ptr);
            *ipos = s_ptr->store_ctr - 1;
        }
    }
}

/* Destroy an item in the stores inventory.  Note that if	*/
/* "one_of" is false, an entire slot is destroyed	-RAK-	*/
void store_destroy(store_num, item_val, one_of) int store_num, item_val;
int one_of;
{
    int j, number;
    store_type *s_ptr;
    inven_type *inventory_p;

    s_ptr = &store[store_num];
    inventory_p = &s_ptr->store_inven[item_val].sitem;

    /* for single stackable objects, only destroy one half on average,
       this will help ensure that general store and alchemist have
       reasonable selection of objects */
    if ((inventory_p->item_subcategory >= ITEM_SINGLE_STACK_MIN) &&
        (inventory_p->item_subcategory <= ITEM_SINGLE_STACK_MAX)) {
        if (one_of)
            number = 1;
        else
            number = randint((int)inventory_p->number);
    } else
        number = inventory_p->number;

    if (number != inventory_p->number)
        inventory_p->number -= number;
    else {
        for (j = item_val; j < s_ptr->store_ctr - 1; j++)
            s_ptr->store_inven[j] = s_ptr->store_inven[j + 1];
        invcopy(&s_ptr->store_inven[s_ptr->store_ctr - 1].sitem, OBJ_NOTHING);
        s_ptr->store_inven[s_ptr->store_ctr - 1].scost = 0;
        s_ptr->store_ctr--;
    }
}

/* Initializes the stores with owners			-RAK-	*/
void store_init() {
    int i, j, k;
    store_type *s_ptr;

    i = MAX_OWNERS / MAX_STORES;
    for (j = 0; j < MAX_STORES; j++) {
        s_ptr = &store[j];
        s_ptr->owner = MAX_STORES * (randint(i) - 1) + j;
        s_ptr->insult_cur = 0;
        s_ptr->store_open = 0;
        s_ptr->store_ctr = 0;
        s_ptr->good_buy = 0;
        s_ptr->bad_buy = 0;
        for (k = 0; k < STORE_INVEN_MAX; k++) {
            invcopy(&s_ptr->store_inven[k].sitem, OBJ_NOTHING);
            s_ptr->store_inven[k].scost = 0;
        }
    }
}

/* Creates an item and inserts it into store's inven	-RAK-	*/
static void store_create(store_num) int store_num;
{
    int i, tries;
    int cur_pos, dummy;
    store_type *s_ptr;
    inven_type *t_ptr;

    tries = 0;
    cur_pos = popt();
    s_ptr = &store[store_num];
    do {
        i = store_choice[store_num][randint(STORE_CHOICES) - 1];
        invcopy(&t_list[cur_pos], i);
        magic_treasure(cur_pos, OBJ_TOWN_LEVEL);
        t_ptr = &t_list[cur_pos];
        if (store_check_num(t_ptr, store_num)) {
            if ((t_ptr->cost > 0) && /* Item must be good	*/
                (t_ptr->cost < owners[s_ptr->owner].max_cost)) {
                /* equivalent to calling ident_spell(), except will not
                   change the object_ident array */
                store_bought(t_ptr);
                store_carry(store_num, &dummy, t_ptr);
                tries = 10;
            }
        }
        tries++;
    } while (tries <= 3);
    pusht((int8u)cur_pos);
}

/* Initialize and up-keep the store's inventory.		-RAK-	*/
void store_maint() {
    int i, j;
    store_type *s_ptr;

    for (i = 0; i < MAX_STORES; i++) {
        s_ptr = &store[i];
        s_ptr->insult_cur = 0;
        if (s_ptr->store_ctr >= STORE_MIN_INVEN) {
            j = randint(STORE_TURN_AROUND);
            if (s_ptr->store_ctr >= STORE_MAX_INVEN)
                j += 1 + s_ptr->store_ctr - STORE_MAX_INVEN;
            while (--j >= 0)
                store_destroy(i, randint((int)s_ptr->store_ctr) - 1, FALSE);
        }

        if (s_ptr->store_ctr <= STORE_MAX_INVEN) {
            j = randint(STORE_TURN_AROUND);
            if (s_ptr->store_ctr < STORE_MIN_INVEN)
                j += STORE_MIN_INVEN - s_ptr->store_ctr;
            while (--j >= 0)
                store_create(i);
        }
    }
}

/* eliminate need to bargain if player has haggled well in the past   -DJB- */
int noneedtobargain(store_num, minprice)
int store_num;
int32 minprice;
{
    int flagnoneed;
    int bargain_record;
    store_type *s_ptr;

    s_ptr = &store[store_num];
    if (s_ptr->good_buy == MAX_SHORT)
        return TRUE;
    bargain_record = (s_ptr->good_buy - 3 * s_ptr->bad_buy - 5);
    flagnoneed =
        ((bargain_record > 0) &&
         ((long)bargain_record * (long)bargain_record > minprice / 50));
    return (flagnoneed);
}

/* update the bargin info					-DJB- */
void updatebargain(store_num, price, minprice) int store_num;
int32 price, minprice;
{
    store_type *s_ptr;

    s_ptr = &store[store_num];
    if (minprice > 9)
        if (price == minprice) {
            if (s_ptr->good_buy < MAX_SHORT)
                s_ptr->good_buy++;
        } else {
            if (s_ptr->bad_buy < MAX_SHORT)
                s_ptr->bad_buy++;
        }
}

