/* Displays a store's inventory				-RAK-	*/
static void display_inventory(store_num, start) int store_num, start;
{
    store_type *s_ptr;
    inven_type *inventory_p;
    int i, j, stop;
    bigvtype out_val1, out_val2;
    int32 x;

    s_ptr = &store[store_num];
    i = (start % 12);
    stop = ((start / 12) + 1) * 12;
    if (stop > s_ptr->store_ctr)
        stop = s_ptr->store_ctr;
    while (start < stop) {
        inventory_p = &s_ptr->store_inven[start].sitem;
        x = inventory_p->number;
        if ((inventory_p->item_subcategory >= ITEM_SINGLE_STACK_MIN) &&
            (inventory_p->item_subcategory <= ITEM_SINGLE_STACK_MAX))
            inventory_p->number = 1;
        objdes(out_val1, inventory_p, TRUE);
        inventory_p->number = x;
        (void)sprintf(out_val2, "%c) %s", 'a' + i, out_val1);
        prt(out_val2, i + 5, 0);
        x = s_ptr->store_inven[start].scost;
        if (x <= 0) {
            int32 value = -x;
            value = value * chr_adj() / 100;
            if (value <= 0)
                value = 1;
            (void)sprintf(out_val2, "%9ld", value);
        } else
            (void)sprintf(out_val2, "%9ld [Fixed]", x);
        prt(out_val2, i + 5, 59);
        i++;
        start++;
    }
    if (i < 12)
        for (j = 0; j < (11 - i + 1); j++)
            erase_line(j + i + 5, 0); /* clear remaining lines */
    if (s_ptr->store_ctr > 12)
        put_buffer("- cont. -", 17, 60);
    else
        erase_line(17, 60);
}

/* Re-displays only a single cost			-RAK-	*/
static void display_cost(store_num, pos) int store_num, pos;
{
    int i;
    int32 j;
    vtype out_val;
    store_type *s_ptr;

    s_ptr = &store[store_num];
    i = (pos % 12);
    if (s_ptr->store_inven[pos].scost < 0) {
        j = -s_ptr->store_inven[pos].scost;
        j = j * chr_adj() / 100;
        (void)sprintf(out_val, "%ld", j);
    } else
        (void)sprintf(out_val, "%9ld [Fixed]", s_ptr->store_inven[pos].scost);
    prt(out_val, i + 5, 59);
}

